package $reference ManufacturingSchema lower JavaPackage$.$reference ManufacturingSchema lower SchemaName$;

import java.util.Comparator;

/*
 *	The $SchemaName$RoleInfoDependencyComparator objects are passed in to the $SecSchemaName$ schema implementation to be bound
 *	to the security system.  Their natural order is to compare by dependency first, and by name second.
 */
public class $SchemaName$RoleInfoDependencyComparator implements Comparator<$SchemaName$RoleInfo>
{
	@Override
	public int compare( $SchemaName$RoleInfo lhs, $SchemaName$RoleInfo rhs ) {
		if( lhs == null ) {
			if ( rhs == null ) {
				return( 0 );
			}
			else {
				return( -1 );
			}
		}
		else if( rhs == null ) {
			return( 1 );
		}
		else {
			String lhsName = lhs.getRoleName();
			String rhsName = rhs.getRoleName();
			String lhsMembership = lhs.getMembership();
			String rhsMembership = rhs.getMembership();
			String lhsMembers[] = lhsMembership.split(" ");
			String rhsMembers[] = rhsMembership.split(" ");
			boolean rhsEnablesLhs = false;
			boolean lhsEnablesRhs = false;
			for (String v: lhsMembers) {
				if (rhsName.equals(v)) {
					lhsEnablesRhs = true;
					break;
				}
			}
			for (String v: rhsMembers) {
				if (lhsName.equals(v)) {
					rhsEnablesLhs = true;
					break;
				}
			}
			int ret;
			if (lhsEnablesRhs) {
				if (rhsEnablesLhs) {
					ret = lhsName.compareTo(rhsName);
				}
				else {
					ret = 1;
				}
			}
			else {
				if (rhsEnablesLhs) {
					ret = -1;
				}
				else {
					ret = lhsName.compareTo(rhsName);
				}
			}
			return( ret );
		}
	}
}
